    </div>
  </section>

  <!-- ====== FECHAMENTO — gerar plano dos selecionados ====== -->
  <div class="gen-box">
    <span class="live-indicator" id="live-indicator"></span>
    <h2>⚙️ Gerar plano dos selecionados</h2>‹revisar?›
    <p class="gen-intro">Marque o que vira ação acima. Com o daemon ligado (<code class="inline">live sync</code>), eu já leio o que você escolheu — é só dizer "ok" no CLI. Sem daemon, o botão copia pro clipboard.</p>
    <div class="gen-progress"><b id="gen-done">0</b>&nbsp;de&nbsp;<span id="gen-total">0</span>&nbsp;achados viram ação<div class="gen-bar"><div class="gen-bar-fill" id="gen-bar"></div></div></div>
    <div class="gen-note"><label for="gen-comments">Algo a acrescentar ao plano? (opcional)</label><textarea id="gen-comments" placeholder="Ex: prioriza o refator #3 antes do resto..."></textarea></div>
    <div class="sticky-actions"><button class="btn btn-primary" onclick="genPlan(this)">⚙️ Gerar plano dos selecionados</button></div>
  </div>

</div>

<script>
var STORAGE_KEY = 'claude-visual:' + location.pathname;
function onFb(input) {
  var item = input.closest('.feedback-item');
  item.classList.remove('state-keep','state-change','state-remove');
  item.classList.add('state-' + input.value);
  updateGenProgress(); saveState();
}
function updateGenProgress() {
  var items = document.querySelectorAll('.feedback-item'); var total = items.length; var act = 0;
  items.forEach(function(it){ var c = it.querySelector('input:checked'); if (c && (c.value==='keep'||c.value==='change')) act++; });
  var d = document.getElementById('gen-done'), t = document.getElementById('gen-total'), b = document.getElementById('gen-bar');
  if (d) d.textContent = act; if (t) t.textContent = total; if (b) b.style.width = total ? (100*act/total)+'%' : '0%';
}
function collectSelected() {
  var byCat = {}; var order = [];
  document.querySelectorAll('.feedback-item').forEach(function(it){
    var c = it.querySelector('input:checked'); if (!c) return;
    if (c.value !== 'keep' && c.value !== 'change') return;
    var cat = it.dataset.cat; if (!byCat[cat]) { byCat[cat] = []; order.push(cat); }
    var line = '- ' + it.dataset.title;
    if (c.value === 'change') {
      var ta = it.querySelector('.feedback-textarea'); var note = (ta && ta.value || '').trim();
      line += ' — _ajuste:_ ' + (note || '(descrever no CLI)');
    }
    byCat[cat].push(line);
  });
  return { byCat: byCat, order: order };
}
function genPlan(btn) {
  var sel = collectSelected();
  var lines = ['<!-- visual-feedback v1 -->', '⚙️ **Actionables do relatório /qa-loop — viram o próximo plano:**', ''];
  if (!sel.order.length) { lines.push('_(nenhum item marcado como ação)_'); }
  else { sel.order.forEach(function(cat){ lines.push('**' + cat + '**'); lines = lines.concat(sel.byCat[cat]); lines.push(''); }); }
  var c = document.getElementById('gen-comments'); var cText = (c && c.value || '').trim();
  if (cText) { lines.push('**Observação:**', cText, ''); }
  lines.push('Monta o plano só com estes itens.', '', '<!-- /visual-feedback -->');
  copyText(lines.join('\n')).then(function(){ flashBtn(btn,'Copiado — cola no CLI'); }).catch(function(){ flashBtn(btn,'Falha — copie manual', true); });
}
function copyText(text) {
  if (navigator.clipboard && navigator.clipboard.writeText) return navigator.clipboard.writeText(text);
  return new Promise(function(res, rej){ var ta=document.createElement('textarea'); ta.value=text; ta.style.position='fixed'; ta.style.opacity='0'; document.body.appendChild(ta); ta.select(); var ok=false; try{ok=document.execCommand('copy');}catch(e){} document.body.removeChild(ta); ok?res():rej(); });
}
function flashBtn(btn, label, isErr) { var o=btn.textContent; btn.textContent=(isErr?'✗ ':'✓ ')+label; btn.classList.add('copied'); setTimeout(function(){btn.textContent=o; btn.classList.remove('copied');},2600); }
function buildStateSnapshot() {
  return { feedback: Array.from(document.querySelectorAll('.feedback-item')).map(function(it){
    var c = it.querySelector('input:checked'); var ta = it.querySelector('.feedback-textarea');
    return { num: it.dataset.num, cat: it.dataset.cat, title: it.dataset.title, val: c?c.value:null, note: ta?ta.value:'' };
  }), comments: (document.getElementById('gen-comments')||{}).value || '' };
}
function saveState(){ try{ localStorage.setItem(STORAGE_KEY, JSON.stringify(buildStateSnapshot())); }catch(e){} postState(); }
var _t=null; var URL_ = (window.VISUAL_SERVER_URL||'http://127.0.0.1:7755')+'/state';
function postState(){ if(!window.VISUAL_SESSION) return; if(_t) clearTimeout(_t);
  _t=setTimeout(function(){ try{ fetch(URL_,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({session:window.VISUAL_SESSION,docTitle:document.title,state:buildStateSnapshot()}),keepalive:true})
    .then(function(r){ var i=document.getElementById('live-indicator'); if(i) i.className=r.ok?'live-indicator ok':'live-indicator err'; })
    .catch(function(){ var i=document.getElementById('live-indicator'); if(i) i.className='live-indicator err'; }); }catch(e){} }, 400); }
function restoreState(){ try{ var raw=localStorage.getItem(STORAGE_KEY); if(!raw) return; var s=JSON.parse(raw);
  if(s.feedback) s.feedback.forEach(function(f){ if(!f.val) return; var it=document.querySelector('.feedback-item[data-num="'+f.num+'"]'); if(!it) return;
    it.classList.remove('state-keep','state-change','state-remove'); it.classList.add('state-'+f.val);
    var r=it.querySelector('input[value="'+f.val+'"]'); if(r) r.checked=true; var ta=it.querySelector('.feedback-textarea'); if(ta&&f.note) ta.value=f.note; });
  if(s.comments){ var c=document.getElementById('gen-comments'); if(c) c.value=s.comments; } }catch(e){} }
document.addEventListener('DOMContentLoaded', function(){
  restoreState(); updateGenProgress();
  document.querySelectorAll('.feedback-textarea').forEach(function(ta){ ta.addEventListener('input', saveState); });
  var c=document.getElementById('gen-comments'); if(c) c.addEventListener('input', saveState);
});
</script>
</body>
</html>
